var getDialogsToolShape = {
  limit: external_exports.number().int().min(1).max(100).default(50).describe("Maximum number of dialogs to retrieve (default: 50, max: 100)"),
  archived: external_exports.boolean().default(false).describe("If true, get archived chats. If false, get active chats."),
  unreadOnly: external_exports.boolean().default(false).describe("If true, only return dialogs with unread messages.")
};
var getDialogsInputSchema = external_exports.object(getDialogsToolShape);
async function handleGetDialogs(bridge, input) {
  const parsed = getDialogsInputSchema.parse(input);
  const dialogs = await bridge.getDialogs({
    limit: parsed.limit,
    archived: parsed.archived
  });
  const filteredDialogs = parsed.unreadOnly ? dialogs.filter((dialog) => dialog.unreadCount > 0) : dialogs;
  const totalUnread = filteredDialogs.reduce(
    (sum, dialog) => sum + dialog.unreadCount,
    0
  );
  const totalMentions = filteredDialogs.reduce(
    (sum, dialog) => sum + dialog.unreadMentionsCount,
    0
  );
  return {
    dialogs: filteredDialogs,
    count: filteredDialogs.length,
    totalUnread,
    totalMentions,
    summary: `${filteredDialogs.length} chats, ${totalUnread} unread messages, ${totalMentions} mentions`
  };
}

