// src/tools/messaging/schedule-message.ts
function parseScheduleTimestamp(scheduleDate) {
  const trimmed = scheduleDate.trim();
  if (/^\d+$/.test(trimmed)) {
    const unix2 = Number.parseInt(trimmed, 10);
    return Number.isFinite(unix2) ? unix2 : null;
  }
  const parsedDate = new Date(trimmed);
  if (!Number.isNaN(parsedDate.getTime())) {
    return Math.floor(parsedDate.getTime() / 1e3);
  }
  const unix = Number.parseInt(trimmed, 10);
  if (!Number.isFinite(unix)) {
    return null;
  }
  return unix;
}
var scheduleMessageToolShape = {
  chatId: external_exports.string().trim().min(1).describe("The chat ID to send the scheduled message to"),
  text: external_exports.string().min(1).max(4096).describe("The message text to send (max 4096 characters)"),
  scheduleDate: external_exports.string().min(1).describe(
    "When to send the message (ISO 8601 or Unix timestamp as string)"
  )
};
var scheduleMessageInputSchema = external_exports.object(scheduleMessageToolShape).superRefine((data, ctx) => {
  const scheduleTimestamp = parseScheduleTimestamp(data.scheduleDate);
  if (scheduleTimestamp === null) {
    ctx.addIssue({
      code: external_exports.ZodIssueCode.custom,
      message: "Invalid scheduleDate format. Use ISO 8601 (e.g. '2024-12-25T10:00:00Z') or Unix timestamp."
    });
    return;
  }
  const now = Math.floor(Date.now() / 1e3);
  if (scheduleTimestamp <= now) {
    ctx.addIssue({
      code: external_exports.ZodIssueCode.custom,
      message: "Schedule date must be in the future"
    });
  }
});
async function handleScheduleMessage(bridge, input) {
  const parsed = scheduleMessageInputSchema.parse(input);
  const scheduleTimestamp = parseScheduleTimestamp(parsed.scheduleDate);
  if (scheduleTimestamp === null) {
    throw new Error("Invalid scheduleDate");
  }
  return bridge.scheduleMessage({
    chatId: parsed.chatId,
    text: parsed.text,
    scheduleTimestamp
  });
}

