function isVisionAnalyzeEnabled(env = process.env) {
  return Boolean(env.OPENAI_API_KEY);
}
function getTelegramToolRegistry(env = process.env) {
  if (isVisionAnalyzeEnabled(env)) {
    return toolDefinitions;
  }
  return toolDefinitions.filter((def) => def.name !== "vision_analyze");
}
var telegramToolRegistry = getTelegramToolRegistry();
function toolJsonPayload(value) {
  return JSON.stringify(value, null, 2);
}
function registerTelegramTools(server, bridge) {
  for (const def of getTelegramToolRegistry()) {
    server.registerTool(
      def.name,
      {
        description: def.description,
        inputSchema: def.shape,
        _meta: { jsonSchema: def.jsonSchema }
      },
      async (args) => {
        const run = def.handle;
        return {
          content: [
            {
              type: "text",
              text: toolJsonPayload(await run(bridge, args))
            }
          ]
        };
      }
    );
  }
}

// src/server.ts
function createTelegramMcpServer(bridge) {
  const server = new McpServer({
    name: "telegram-mcp",
    version: "0.1.0"
  });
  registerTelegramTools(server, bridge);
  return server;
}

