  const shutdown = async () => {
    try {
      await server.close();
    } finally {
      await disconnect();
    }
  };
  import_node_process2.default.once("SIGINT", () => {
    void shutdown().finally(() => import_node_process2.default.exit(0));
  });
  import_node_process2.default.once("SIGTERM", () => {
    void shutdown().finally(() => import_node_process2.default.exit(0));
  });
